import { FlowStep } from './FlowStep';
import { FlowStepInstruction } from './FlowStepInstruction';
import { StoppingActivityInfo } from './FlowEmissions';

/**
 * Class to produce Flow Harness entries via method chaining interface.
 *
 */

export interface ActivityMatchConditions {
    visits?: number; // That an activity has been visited (executed) this number of times (default: the count of activity visits is ignored).
    result?: string; // That the activity result (after executing the given number of times) is equal to this (default: the result is ignored).
    inFlowUri?: string; // That the activity was executed in a flow Uri that has this string in it (case insensitive), e.g. "subs/sub1.flow", "/sub1", "sub1.flow"
}

export interface FlowHarnessOptions {
    SSM?: any; // The SSM containing the ASR, TTS and Listen Services
    name?: string; // Can be set to an arbitrary string, this will be printed when the harness attaches.
    enableLogging?: boolean; // When set, causes the execution of each harness step to be logged.
}

export class FlowHarness {
    public SSM:any;
    public name:string = '';
    public enableLogging:boolean;

    private _steps:FlowStep[] = [];
    private _activityTrace:StoppingActivityInfo[];

    /**
     * Construct with FlowHarnessOptions that provide:
     * the SSM, which supplies references to ASRService and TTSService.
     * the name (optional) which will be printed when the harness attaches.
     * @param options
     */
    constructor(options:FlowHarnessOptions) {
        // Detect legacy usage and upgrade it to modern usage.
        if ('ASRService' in options) {
            this.SSM = options;
        } else {
            this.SSM = options.SSM;
            this.name = options.name || this.name;
            this.enableLogging = options.enableLogging;
        }
    }

    /**
     * Create a chainable-method flowstep object initialized to a copy of the baseline.
     * @returns {FlowStep}
     */
    when():FlowStep {
        let step = new FlowStep();
        this._steps.push(step);
        return step;
    }

    // TODO: implement "always" which keeps a separate list of stubbings, etc. that are always in effect.
    // always() { }

    /**
     * Return the harness instructions as an array.
     * @returns {any}
     */
    getSteps():FlowStepInstruction[] {
        let stepInstructions:FlowStepInstruction[] = [];
        for (let step of this._steps) {
            stepInstructions.push(step.getStep());
        }
        return stepInstructions;
    }

    getStep(n):FlowStepInstruction {
        return this._steps[n].getStep();
    }

    getLength():number {
        return this._steps.length;
    }

    /**
     * Check all the harness' steps for consistency.
     */
    checkSteps():void {
        for (let step of this._steps) {
            step.checkStep();
        }
    }

    /**
     * A method to allow the FlowHarnesser to attach the ongoing executing trace from the FlowExecutor.
     * @param activityTrace
     */
    attachTrace(activityTrace:StoppingActivityInfo[]) {
        this._activityTrace = activityTrace;
    }

    /**
     * Return true if all the steps of the harness were executed.
     * @returns {boolean}
     */
    didExecuteAllSteps() {
        for (let step of this._steps) {
            if (!step.getStep().executed) {
                return false;
            }
        }
        return true;
    }

    /**
     * Return true if the named activity was executed (with the given conditions) during the course of the flow's execution.
     * @param {string} activityName name of activity in question
     * @param {ActivityMatchConditions} [conditions] specifies match options.
     * @returns {boolean}
     */

    didExecuteActivity(activityName: string, conditions: ActivityMatchConditions = {}) {
        let visits = {};
        let result = {};
    
        for (let activity of this._activityTrace) {
            if (!conditions.inFlowUri || activity.uri.toLowerCase().includes(conditions.inFlowUri.toLowerCase())) {
                visits[activity.name] = (visits[activity.name] || 0) + 1;
                result[activity.name] = activity.result;
            }
        }
        return (
            activityName in visits
            && (conditions.visits === undefined || visits[activityName] === conditions.visits)
            && (conditions.result === undefined || result[activityName] === conditions.result)
        );
    }
}

