
import { FlowStepInstruction } from './FlowStepInstruction';

/**
 * This creates a single step in a Flow Harness. They may be chained together,
 * e.g. FlowHarnessInstance.step().say('hey jibo').at.activityName('Waiting for user')
 * in order to express an assertion or action to be taken at a specific point in a flow.
 */
export class FlowStep {
    private _step = new FlowStepInstruction();

    /**
     * Produce simulated ASR input
     * @param text ASR input to synthesize
     * @returns {FlowStep}
     */
    say(text:string):FlowStep {
        this._ensureSettable('say', text);
        this._step.say = text;
        return this;
    }

    awaitingSpeechInput():FlowStep {
        this._step.awaitingSpeechInput = true;
        return this;
    }

    /**
     * "Stub out" a flow activity, supplying a function that will be called to produce the result.
     * @param resultFunction
     * @returns {FlowStep}
     */
    stub(stubFunction:(activity, notepad, blackboard)=>string):FlowStep {
        this._ensureSettable('at', 'start');
        this._ensureSettable('stub');
        this._step.at = 'start';
        this._step.stub = stubFunction;
        return this;
    }

    /**
     * Execute a function during some phase of an activity's execution cycle.
     * @param func
     * @returns {FlowStep}
     */
    do(func:(activity, notepad, blackboard)=>string):FlowStep {
        this._ensureSettable('do');
        this._step.do = func;
        return this;
    }

    /**
     * After the intended activity is identified, this causes a delay before the action is taken.
     * @param seconds
     * @returns {FlowStep}
     */
    delay(seconds:number):FlowStep {
        this._step.delay = seconds;
        return this;
    }

    /**
     * Force the identified activity to take the given transition after it has executed.
     * @param transition
     * @returns {FlowStep}
     */
    forceTransition(transition:string):FlowStep {
        this._ensureSettable('at', 'end');
        this._ensureSettable('stub');
        this._step.at = 'end';
        this._step.stub = ()=>transition;
        return this;
    }

    /**
     * Force the identified activity to take the given transition during execution.
     * @param transition
     * @returns {FlowStep}
     */
    activeTransition(transition:string):FlowStep {
        this._ensureSettable('at', 'update');
        this._ensureSettable('stub');
        this._step.at = 'update';
        this._step.stub = ()=>transition;
        return this;
    }

    /**
     * Assert some condition about the state of flow at the identified activity.
     * @param assertionTest
     * @param text
     * @returns {FlowStep}
     */
    assert(assertionTest:(activity, notepad, blackboard)=>boolean, message?:string):FlowStep {
        this._ensureSettable('at','end');
        this._ensureSettable('it');
        this._ensureSettable('assert');
        this._step.at = 'end';
        this._step.it = message;
        this._step.assert = assertionTest;
        return this;
    }

    /**
     * Identify an activity, by name, that we intend to perform an action at.
     * @param activityName
     * @returns {FlowStep}
     */
    activityName(activityName:string):FlowStep {
        this._ensureSettable('activity');
        this._step.activity = activityName;
        return this;
    }

    /**
     * Cause action to be performed at the "start" phase of the activity execution.
     * @param activityName
     * @returns {FlowStep}
     */
    before():FlowStep {
        this._ensureSettable('at', 'start');
        this._step.at = 'start';
        return this;
    }

    /**
     * Cause action to be performed at the "update" phase of the activity execution.
     * @param activityName
     * @returns {FlowStep}
     */
    at():FlowStep {
        this._ensureSettable('at', 'update');
        this._step.at = 'update';
        return this;
    }

    /**
     * Cause action to be performed at the "end" phase of the activity execution.
     * @param activityName
     * @returns {FlowStep}
     */
    after():FlowStep {
        this._ensureSettable('at', 'end');
        this._step.at = 'end';
        return this;
    }

    /**
     * Identify a flow page, by name (without the .flow extension) that we intend to perform an action at.
     * @param flowName
     * @returns {FlowStep}
     */
    inFlow(flowName:string):FlowStep {
        this._ensureSettable('flow');
        this._step.flow = flowName;
        return this;
    }

    /**
     * Identify an activity type (e.g. Flow.Begin) that we intend to perform an action at.
     * @param activityType
     * @returns {FlowStep}
     */
    activityType(activityType:string):FlowStep {
        this._ensureSettable('class');
        this._step.class = activityType;
        return this;
    }

    /**
     * Identify an activity ID (e.g. "7596440b-9294-473d-95da-8d44e3d96792") that we intend to perform an action at.
     * @param activityId
     * @returns {FlowStep}
     */
    activityId(activityId:string):FlowStep {
        this._ensureSettable('id');
        this._step.id = activityId;
        return this;
    }

    /**
     * Identify the number of times an activity must be executed before we will match it.
     * (default: any number of times)
     * @param count
     * @returns {FlowStep}
     */

    visits(count:number):FlowStep {
        this._ensureSettable('visits', count);
        this._step.visits = count;
        return this;
    }

    /**
     * Check the accumulated settings for consistency.
     * @returns {any}
     */
    checkStep():void {
        if (this._step.delay && this._step.at && this._step.at !== 'update') {
            throw new Error('Delay operation only permitted during "update" cycle.');
        }
    }

    /**
     * Ensure that a user is not trying to set a property to conflicting values.
     * @param prop
     * @param value
     * @private
     */
    _ensureSettable(prop:string, value?:string|number) {
        if (this._step[prop] !== undefined && value === undefined) {
            throw new Error(`FlowStep: Cannot set step property ${prop} a second time`);
        }
        if (this._step[prop] !== undefined && this._step[prop] !== value) {
            throw new Error(`FlowStep: Cannot set step property ${prop} to ${value} after setting it to ${this._step[prop]}`);
        }
    }

    /**
     * Return the harness instruction that has been assembled from all the invoked methods.
     * @returns {any}
     */
    getStep():FlowStepInstruction {
        return this._step;
    }
}

