import FlowRoot from './FlowRoot';
import TreeLoader from './loaders/TreeLoader';
import GojsLoader from './loaders/GojsLoader';

/**
 * A factory that returns a FlowRoot instance given a start URI.
 * @class FlowRootFactory
 * @memberof module:jibo-flow-core
 * @intdocs
 */
class FlowRootFactory {
    /**
     * Create a FlowRoot (a ready to execute Flow Program) from a .flow file or a function. 
     * @method jibo.flow.FlowRootFactory#create
     * @param {string} uri A .flow filename or a Javascript function 
     * that will return the Behaviorify produced Tree for the Flow.
     * @param {any} [loader] An optionally supplied loader to use for loading procedures.
     * @returns {jibo.flow.FlowRoot}
     */
    public static create(uri:any, loader?:any):FlowRoot {

        if (loader === undefined) {
            if (typeof(uri) === 'function') {
                loader = TreeLoader;

            } else if (uri.endsWith(".flow")) {
                loader = new GojsLoader();

            } else {
                console.error('FlowRootFactory encountered an unknown file type: ' + uri);
                throw new Error('FlowRootFactory encountered an unknown file type: ' + uri);
            }
        }

        let flowRoot = new FlowRoot(loader);
        flowRoot.setStartInfoFromUri(uri);
        return flowRoot;
    }
}

export default FlowRootFactory;
