/**
 * One instruction step of a FlowHarness.
 * This controls where in a running flow a harness step will occur, and what will happen when the step is executed.
 */

export class FlowStepInstruction {
    // Instruction "inputs":
    // Location info:
    public activity:string; // Flow activity name
    public class:string; // Flow activity class, e.g. 'Flow.Begin'
    public flow:string; // Flow name (.flow file without the '.flow' extension).
    public id:string; // flow activity UUID
    public visits:number; // locate the activity by the number of times it has been executed.
    public awaitingSpeechInput:boolean; // when set, this step is ready to execute when a Dialog Listener has subscribed.

    // Location modifiers:
    public at:string; // 'start', 'update', 'end', default if unset is 'update'
    public delay:number; // number of seconds to delay after step is matched before it is executed.

    // Verbs:
    public stub:(activity, notepad, blackboard)=>string; // function result is the activity's transition.
    public assert:(activity, notepad, blackboard)=>boolean; // function result is whether the assert succeeded or failed.
    public do:(activity, notepad, blackboard)=>string; // function result is the activity's transition if "at" is 'end'.
    public say:string; // synthetic ASR input (as a text string of speech)

    // Adverbs:
    public it:string; // message to print on assertions

    // Instruction "outputs"
    public executed:boolean; // Records whether the instruction actually ran
    public result:any; // Whatever the stub or do returned.
    public assertion:boolean; // Whatever the assert returned
    public timestamp:number; // when the instruction first matched (for implementing "delay")
    public listenerIsSubscribed:boolean; // when a step is awaiting speech input, this will be false until a listener is waiting.
}

